<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Discovery — 24 Bots</title>
<style>
  :root{
    --bg:#0f1420; --panel:#171d2b; --accent:#7dd3fc; --wall:#e2e8f0; --text:#e5e9f0;
  }
  *{box-sizing:border-box;}
  body{
    margin:0; min-height:100vh; background:var(--bg); color:var(--text);
    font-family:-apple-system,Segoe UI,Roboto,sans-serif;
    display:flex; flex-direction:column; align-items:center; padding:20px;
  }
  h1{font-size:20px; margin:4px 0 12px; color:var(--accent); letter-spacing:.5px;}
  .panel{
    display:flex; gap:16px; align-items:center; background:var(--panel);
    padding:10px 16px; border-radius:10px; margin-bottom:14px; flex-wrap:wrap;
    box-shadow:0 2px 8px rgba(0,0,0,.4);
  }
  .stat{font-size:14px; display:flex; gap:6px; align-items:baseline;}
  .stat b{font-size:18px; color:var(--accent);}
  button#reset{
    background:#3b4a6b; color:#fff; border:none; padding:8px 16px; border-radius:8px;
    cursor:pointer; font-size:14px; font-weight:600; transition:background .15s;
  }
  button#reset:hover{background:#4d5f8a;}
  #maze{
    background:#0b0f18; border-radius:8px; padding:6px; box-shadow:0 4px 20px rgba(0,0,0,.5);
    line-height:0;
  }
  canvas{display:block; border-radius:4px;}
  .legend{font-size:11px; color:#8891a8; margin-top:10px; display:flex; gap:14px;}
  .dot{display:inline-block; width:9px; height:9px; border-radius:50%; margin-right:4px;}
</style>
</head>
<body>
<h1>Maze Discovery — 24 Autonomous Bots</h1>
<div class="panel">
  <div class="stat">Completed: <b id="completed">0</b>/24</div>
  <div class="stat">Ticks: <b id="timer">0</b></div>
  <button id="reset">Reset (new maze)</button>
</div>
<div id="maze"><canvas id="canvas"></canvas></div>
<div class="legend">
  <span><span class="dot" style="background:#7dd3fc"></span>Spawn</span>
  <span><span class="dot" style="background:#facc15"></span>Exit</span>
  <span>Bots discover the maze via Tremaux-style DFS — no global knowledge</span>
</div>

<script>
(function(){
  "use strict";

  const ROWS = 17, COLS = 17, BOT_COUNT = 24, CELL = 24, PAD = 5;
  const AUTOPLAY_INTERVAL = 80;

  const canvas = document.getElementById('canvas');
  const ctx = canvas.getContext('2d');
  canvas.width = COLS * CELL + PAD * 2;
  canvas.height = ROWS * CELL + PAD * 2;

  const completedEl = document.getElementById('completed');
  const timerEl = document.getElementById('timer');
  const resetBtn = document.getElementById('reset');

  // ---------- deterministic RNG ----------
  function mulberry32(seed){
    let a = seed >>> 0;
    return function(){
      a = (a + 0x6D2B79F5) | 0;
      let t = Math.imul(a ^ (a >>> 15), 1 | a);
      t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
      return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
    };
  }
  function shuffled(arr, rng){
    const a = arr.slice();
    for(let i=a.length-1;i>0;i--){
      const j = Math.floor(rng()*(i+1));
      const tmp=a[i]; a[i]=a[j]; a[j]=tmp;
    }
    return a;
  }

  // ---------- maze generation (recursive backtracker => perfect maze) ----------
  const DIRS = [
    ['n',-1,0,'s'], ['e',0,1,'w'], ['s',1,0,'n'], ['w',0,-1,'e']
  ];
  function generateMaze(rows, cols, rng){
    const grid = [];
    for(let r=0;r<rows;r++){
      const row=[];
      for(let c=0;c<cols;c++) row.push({n:true,e:true,s:true,w:true});
      grid.push(row);
    }
    const visited = Array.from({length:rows},()=>new Array(cols).fill(false));
    const stack=[{r:0,c:0}];
    visited[0][0]=true;
    while(stack.length){
      const cur = stack[stack.length-1];
      const options=[];
      for(const [d,dr,dc,opp] of DIRS){
        const nr=cur.r+dr, nc=cur.c+dc;
        if(nr>=0 && nr<rows && nc>=0 && nc<cols && !visited[nr][nc]) options.push([d,nr,nc,opp]);
      }
      if(options.length){
        const [d,nr,nc,opp] = options[Math.floor(rng()*options.length)];
        grid[cur.r][cur.c][d]=false;
        grid[nr][nc][opp]=false;
        visited[nr][nc]=true;
        stack.push({r:nr,c:nc});
      } else {
        stack.pop();
      }
    }
    return grid;
  }

  // ---------- bot logic ----------
  const NEIGH = { n:[-1,0], e:[0,1], s:[1,0], w:[0,-1] };

  function makeBot(id, spawn, botSeed){
    const rng = mulberry32(botSeed);
    const dirPref = shuffled(['n','e','s','w'], rng);
    return {
      id,
      r: spawn.r, c: spawn.c,
      prevR: spawn.r, prevC: spawn.c,
      stack: [],
      visited: new Set([spawn.r+','+spawn.c]),
      deadEndSet: new Set(),
      deadEnds: [],
      path: [{r:spawn.r, c:spawn.c}],
      finishTick: null,
      dirPref,
      rng,
      color: `hsl(${(id*151)%360},72%,55%)`
    };
  }

  // one bot advances exactly one cell (Tremaux/DFS: explore unvisited passage,
  // else backtrack & mark dead end). Uses only the walls of its CURRENT cell —
  // no global maze knowledge or pathfinding.
  function stepBot(bot, mazeGrid, exit, tickNum){
    if(bot.finishTick !== null) return;
    bot.prevR = bot.r; bot.prevC = bot.c;

    const cell = mazeGrid[bot.r][bot.c];
    let candidates = [];
    for(const d of bot.dirPref){
      if(!cell[d]){
        const [dr,dc] = NEIGH[d];
        const nr = bot.r+dr, nc = bot.c+dc;
        const key = nr+','+nc;
        if(!bot.visited.has(key)) candidates.push({r:nr,c:nc,key});
      }
    }
    if(candidates.length > 1) candidates = shuffled(candidates, bot.rng);

    if(candidates.length){
      const next = candidates[0];
      bot.stack.push({r:bot.r, c:bot.c});
      bot.r = next.r; bot.c = next.c;
      bot.visited.add(next.key);
      bot.path.push({r:bot.r, c:bot.c});
    } else {
      const dkey = bot.r+','+bot.c;
      if(!bot.deadEndSet.has(dkey)){
        bot.deadEndSet.add(dkey);
        bot.deadEnds.push({r:bot.r, c:bot.c});
      }
      if(bot.stack.length){
        const prev = bot.stack.pop();
        bot.r = prev.r; bot.c = prev.c;
        bot.path.push({r:bot.r, c:bot.c});
      }
      // else: fully explored with nowhere to go (should not occur on a
      // connected perfect maze) — bot simply stays put.
    }

    if(bot.finishTick === null && bot.r === exit.r && bot.c === exit.c){
      bot.finishTick = tickNum;
    }
  }

  // ---------- game state ----------
  let mazeGrid, spawn, exit, bots, tickCounter, finishedCount, currentSeed;

  function doTicksLogical(n){
    for(let i=0;i<n;i++){
      if(finishedCount >= BOT_COUNT) break;
      tickCounter++;
      let anyActive = false;
      for(const bot of bots){
        if(bot.finishTick === null){
          anyActive = true;
          stepBot(bot, mazeGrid, exit, tickCounter);
          if(bot.finishTick !== null) finishedCount++;
        }
      }
      if(!anyActive) { tickCounter--; break; }
    }
  }

  function resetGame(seed){
    currentSeed = (typeof seed === 'number') ? (seed >>> 0) : (Math.floor(Math.random()*4294967295) >>> 0);
    const rng = mulberry32(currentSeed);
    mazeGrid = generateMaze(ROWS, COLS, rng);
    spawn = {r:0, c:0};
    exit = {r: ROWS-1, c: COLS-1};
    bots = [];
    for(let i=0;i<BOT_COUNT;i++){
      const botSeed = Math.floor(rng()*4294967296) >>> 0;
      bots.push(makeBot(i, spawn, botSeed));
    }
    tickCounter = 0;
    finishedCount = 0;
    initRenderState();
  }

  // ---------- public scripting API ----------
  window.game = {
    tick(n){
      n = Math.max(0, n|0);
      doTicksLogical(n);
      snapRenderToLogical();
      updateHud();
    },
    reset(seed){
      resetGame(seed);
      updateHud();
    },
    get elapsed(){ return tickCounter; },
    get size(){ return {rows: ROWS, cols: COLS}; },
    get spawn(){ return {r: spawn.r, c: spawn.c}; },
    get exit(){ return {r: exit.r, c: exit.c}; },
    walls(r, c){
      const cell = mazeGrid[r][c];
      return {n: cell.n, e: cell.e, s: cell.s, w: cell.w};
    },
    get bots(){ return bots; }
  };

  // ---------- rendering ----------
  let renderPos = []; // {x0,y0,x1,y1,t0,dur} per bot for smooth interpolation

  function cellCenter(r, c){
    return { x: PAD + c*CELL + CELL/2, y: PAD + r*CELL + CELL/2 };
  }

  function initRenderState(){
    renderPos = bots.map(b => {
      const p = cellCenter(b.r, b.c);
      return {x0:p.x, y0:p.y, x1:p.x, y1:p.y, t0:0, dur:1};
    });
  }

  // used by the synchronous API: snap instantly to the true logical state
  function snapRenderToLogical(){
    renderPos = bots.map(b => {
      const p = cellCenter(b.r, b.c);
      return {x0:p.x, y0:p.y, x1:p.x, y1:p.y, t0:0, dur:1};
    });
  }

  function updateHud(){
    completedEl.textContent = finishedCount;
    timerEl.textContent = tickCounter;
  }

  function drawMaze(){
    ctx.fillStyle = '#0b0f18';
    ctx.fillRect(0,0,canvas.width,canvas.height);
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 2;
    ctx.lineCap = 'square';
    ctx.beginPath();
    for(let r=0;r<ROWS;r++){
      for(let c=0;c<COLS;c++){
        const cell = mazeGrid[r][c];
        const x = PAD + c*CELL, y = PAD + r*CELL;
        if(cell.n){ ctx.moveTo(x,y); ctx.lineTo(x+CELL,y); }
        if(cell.w){ ctx.moveTo(x,y); ctx.lineTo(x,y+CELL); }
        if(cell.s){ ctx.moveTo(x,y+CELL); ctx.lineTo(x+CELL,y+CELL); }
        if(cell.e){ ctx.moveTo(x+CELL,y); ctx.lineTo(x+CELL,y+CELL); }
      }
    }
    ctx.stroke();

    // spawn marker
    ctx.fillStyle = 'rgba(125,211,252,0.35)';
    ctx.fillRect(PAD + spawn.c*CELL + 3, PAD + spawn.r*CELL + 3, CELL-6, CELL-6);
    // exit marker
    ctx.fillStyle = 'rgba(250,204,21,0.55)';
    ctx.fillRect(PAD + exit.c*CELL + 3, PAD + exit.r*CELL + 3, CELL-6, CELL-6);
  }

  function drawBots(now){
    for(let i=0;i<bots.length;i++){
      const bot = bots[i];
      const anim = renderPos[i];
      let frac = anim.dur > 0 ? Math.min(1, (now - anim.t0) / anim.dur) : 1;
      if(anim.t0 === 0) frac = 1;
      const x = anim.x0 + (anim.x1 - anim.x0) * frac;
      const y = anim.y0 + (anim.y1 - anim.y0) * frac;
      ctx.beginPath();
      ctx.fillStyle = bot.color;
      ctx.arc(x, y, bot.finishTick !== null ? 3.4 : 4.6, 0, Math.PI*2);
      ctx.fill();
      if(bot.finishTick !== null){
        ctx.lineWidth = 1;
        ctx.strokeStyle = 'rgba(255,255,255,0.6)';
        ctx.stroke();
      }
    }
  }

  function renderFrame(){
    const now = performance.now();
    drawMaze();
    drawBots(now);
    requestAnimationFrame(renderFrame);
  }

  // ---------- autoplay (visual demo only; drives via the same logical
  // stepper, animates smoothly between cells, distinct from the
  // synchronous API which snaps instantly and is unaffected in timing
  // since it never yields to this interval mid-call) ----------
  let autoplayHandle = null;
  function startAutoplay(){
    if(autoplayHandle) clearInterval(autoplayHandle);
    autoplayHandle = setInterval(() => {
      if(finishedCount >= BOT_COUNT){
        clearInterval(autoplayHandle);
        autoplayHandle = null;
        return;
      }
      const prev = bots.map(b => ({r:b.r, c:b.c}));
      doTicksLogical(1);
      const now = performance.now();
      renderPos = bots.map((b,i) => {
        const from = cellCenter(prev[i].r, prev[i].c);
        const to = cellCenter(b.r, b.c);
        return {x0:from.x, y0:from.y, x1:to.x, y1:to.y, t0:now, dur:AUTOPLAY_INTERVAL};
      });
      updateHud();
    }, AUTOPLAY_INTERVAL);
  }

  resetBtn.addEventListener('click', () => {
    window.game.reset();
    startAutoplay();
  });

  // ---------- boot ----------
  resetGame();
  updateHud();
  requestAnimationFrame(renderFrame);
  startAutoplay();

})();
</script>
</body>
</html>
